const items = $input.all();

for (const item of items) {
  const status = item.json.status;

  // Base tags (always add)
  const tags = ['woocommerce', 'order_found'];

  // Status-based tags
  if (status === 'completed') {
    tags.push('order_completed');
  } else if (status === 'processing') {
    tags.push('order_processing');
  } else if (status === 'pending') {
    tags.push('order_pending');
  } else if (status === 'cancelled') {
    tags.push('order_cancelled');
  } else if (status === 'refunded') {
    tags.push('order_refunded');
  } else {
    tags.push('order_unknown_status');
  }

  // Attach tags to output
  item.json.zendesk_tags = tags;
}

return items;
